"""Entry point for python -m agentpulse."""

import argparse
from pathlib import Path


def main() -> None:
    """Start the AgentPulse service."""
    import uvicorn

    from agentpulse.config import get_settings, set_config_path

    parser = argparse.ArgumentParser(description="AgentPulse service")
    parser.add_argument(
        "--config",
        type=Path,
        required=True,
        help="Path to config JSON file",
    )
    args = parser.parse_args()

    set_config_path(config_path=args.config)
    settings = get_settings()
    uvicorn.run(
        "agentpulse.app:create_app",
        factory=True,
        host=settings.host,
        port=settings.port,
        log_level="debug" if settings.debug else "info",
    )


if __name__ == "__main__":
    main()
